queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?issue_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasIssues ?child ; p:hasHome_Inspections ?parent . } GROUP BY ?child }
  ?child p:issue_type ?issue_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Home_Inspections } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?address ?issue_type WHERE {
  ?home_inspection_issues a :Home_Inspection_Issues .
  ?issues a :Issues .
  ?home_inspection_issues p:hasIssues ?issues .
  ?home_inspections a :Home_Inspections .
  ?home_inspection_issues p:hasHome_Inspections ?home_inspections .
  ?home_inspections p:address ?address .
  ?issues p:issue_type ?issue_type .
} }
  collective: { SELECT ?issue_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasIssues ?child ; p:hasHome_Inspections ?parent . } GROUP BY ?child }
  ?child p:issue_type ?issue_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Home_Inspections } }
  FILTER(?nf = ?total)
} }
}
